namespace GlitchCompiler.Anomalies { public sealed class ControlInversionAnomaly:IAnomaly { private AnomalyContext context; public string Id=>"control-inversion"; public void OnTrigger(AnomalyContext value){context=value;context.SetTimerMultiplier(context.TimerMultiplier);context.ShowOverlay("操作反轉","輸入 SYSTEM.RESET(); 或按下防護按鈕。");} public bool CheckResolved()=>context.ResetReceived(); public void OnResolve(){context.SetTimerMultiplier(1);context.HideOverlay();} public void OnCleanup(){context.SetTimerMultiplier(1);} } }
